alter table public.grant_settings
  add column if not exists pv_installation_net_per_kwp numeric(12, 2) not null default 500 check (pv_installation_net_per_kwp >= 0),
  add column if not exists roof_sheet_net numeric(12, 2) not null default 1500 check (roof_sheet_net >= 0),
  add column if not exists roof_tile_net numeric(12, 2) not null default 2000 check (roof_tile_net >= 0),
  add column if not exists roof_felt_net numeric(12, 2) not null default 2200 check (roof_felt_net >= 0),
  add column if not exists roof_ground_net numeric(12, 2) not null default 4500 check (roof_ground_net >= 0),
  add column if not exists protections_net numeric(12, 2) not null default 1500 check (protections_net >= 0),
  add column if not exists wiring_net numeric(12, 2) not null default 800 check (wiring_net >= 0),
  add column if not exists transport_net numeric(12, 2) not null default 500 check (transport_net >= 0),
  add column if not exists documentation_net numeric(12, 2) not null default 700 check (documentation_net >= 0),
  add column if not exists monitoring_net numeric(12, 2) not null default 1200 check (monitoring_net >= 0),
  add column if not exists heat_pump_installation_net numeric(12, 2) not null default 0 check (heat_pump_installation_net >= 0),
  add column if not exists marketing_net numeric(12, 2) not null default 500 check (marketing_net >= 0),
  add column if not exists owners_count numeric(6, 2) not null default 3 check (owners_count >= 0),
  add column if not exists pv_small_per_kw_net numeric(12, 2) not null default 250 check (pv_small_per_kw_net >= 0),
  add column if not exists pv_small_fixed_net numeric(12, 2) not null default 500 check (pv_small_fixed_net >= 0),
  add column if not exists pv_large_per_kw_net numeric(12, 2) not null default 150 check (pv_large_per_kw_net >= 0),
  add column if not exists pv_large_fixed_net numeric(12, 2) not null default 700 check (pv_large_fixed_net >= 0),
  add column if not exists heat_pump_per_owner_net numeric(12, 2) not null default 500 check (heat_pump_per_owner_net >= 0),
  add column if not exists operator_percent numeric(5, 2) not null default 15 check (operator_percent >= 0 and operator_percent < 100);
